SELECT [Item Identifier].Code, Item.[Trademark Code], [Item Identifier].[Brand Code], [Item Identifier].[Season Code], [Item Identifier].[Collection Code], [Item Identifier].[Line Code], [Item Identifier].[Model Code], [Item Identifier].[Item No_], [Item Identifier].[Constant Variable Code], [Item Identifier].[Assortment Code], [Item Identifier].Status, [Item Identifier].[Last Location Code Used], [Item Identifier].[Last Bin Code Used]
FROM [Item Identifier] INNER JOIN Item ON [Item Identifier].[Item No_] = Item.No_
WHERE ((([Item Identifier].[Item No_])="F5CPH446/CRO") AND (([Item Identifier].[Constant Variable Code])="BRO") AND (([Item Identifier].[Assortment Code])="CPH03" Or ([Item Identifier].[Assortment Code])="CPH06")) OR ((([Item Identifier].[Item No_])="F5CPH500/VIT") AND (([Item Identifier].[Constant Variable Code])="BLK") AND (([Item Identifier].[Assortment Code])="CPH02")) OR ((([Item Identifier].[Item No_])="F5CPH556/VEG") AND (([Item Identifier].[Constant Variable Code])="BLK") AND (([Item Identifier].[Assortment Code])="CPH02")) OR ((([Item Identifier].[Item No_])="F5CPH570/VIT") AND (([Item Identifier].[Constant Variable Code])="BLK") AND (([Item Identifier].[Assortment Code])="CPH03" Or ([Item Identifier].[Assortment Code])="CPH07")) OR ((([Item Identifier].[Item No_])="F5CPH685/VIT") AND (([Item Identifier].[Constant Variable Code])="BLK") AND (([Item Identifier].[Assortment Code])="CPH01")) OR ((([Item Identifier].[Item No_])="F5CPH686/VIT") AND (([Item Identifier].[Constant Variable Code])="BLB") AND (([Item Identifier].[Assortment Code])="CPH02"));

